const usage = $('Fetch Weekly Usage').item.json;
const health = $('Fetch Provider Health').item.json;

const totalTokens = (usage.totalInputTokens || 0) + (usage.totalOutputTokens || 0);
const totalCostUsd = ((usage.totalCostMicrodollars || 0) / 1_000_000).toFixed(2);
const requestCount = usage.requestCount || 0;
const avgCostPerReq = requestCount > 0 ? ((usage.totalCostMicrodollars || 0) / requestCount / 1_000_000).toFixed(4) : '0.0000';

// Build provider breakdown
const providers = Array.isArray(health) ? health : [];
const providerLines = providers.map(p => {
  const successRate = p.total_requests > 0
    ? ((p.successful_requests / p.total_requests) * 100).toFixed(1)
    : '0.0';
  return `  • **${p.provider_name}**: ${p.total_requests} requests, ${successRate}% success`;
}).join('\n');

// Build per-model breakdown from usage
const models = usage.byModel || [];
const modelLines = models.map(m => {
  const cost = (m.costMicrodollars / 1_000_000).toFixed(4);
  return `  • **${m.model}**: ${m.requests} req, ${m.inputTokens + m.outputTokens} tokens, $${cost}`;
}).join('\n');

const summary = [
  `## 📊 Weekly LLM Cost Digest`,
  `**Period:** ${usage.period || 'Last 7 days'}`,
  '',
  '### Totals',
  `  • **Requests:** ${requestCount.toLocaleString()}`,
  `  • **Tokens:** ${totalTokens.toLocaleString()} (${(usage.totalInputTokens || 0).toLocaleString()} in / ${(usage.totalOutputTokens || 0).toLocaleString()} out)`,
  `  • **Cost:** $${totalCostUsd}`,
  `  • **Avg cost/request:** $${avgCostPerReq}`,
];

if (modelLines) {
  summary.push('', '### By Model', modelLines);
}

if (providerLines) {
  summary.push('', '### Provider Health', providerLines);
}

return [{ json: { digest: summary.join('\n'), totalCostUsd, requestCount, totalTokens } }];
